import 'package:flutter/material.dart';

class ImageIconsDemo extends StatelessWidget {
  const ImageIconsDemo({super.key});

  @override
  Widget build(BuildContext context) {
    return Scaffold(
      appBar: AppBar(title: const Text('Images & Icons')),
      body: Column(
        children: [
          // Image with placeholder
          Container(
            width: 200,
            height: 150,
            decoration: BoxDecoration(
              color: Colors.grey[200],
              borderRadius: BorderRadius.circular(8),
            ),
            child: const Icon(Icons.image, size: 48, color: Colors.grey),
          ),
          const SizedBox(height: 20),
          // Icon row
          const Row(
            mainAxisAlignment: MainAxisAlignment.spaceEvenly,
            children: [
              Icon(Icons.star, size: 32, color: Colors.amber),
              Icon(Icons.favorite, size: 32, color: Colors.red),
              Icon(Icons.thumb_up, size: 32, color: Colors.blue),
              Icon(Icons.share, size: 32, color: Colors.green),
            ],
          ),
          const SizedBox(height: 20),
          // Circle avatars
          const Row(
            mainAxisAlignment: MainAxisAlignment.spaceEvenly,
            children: [
              CircleAvatar(child: Text('AB')),
              CircleAvatar(child: Icon(Icons.person)),
              CircleAvatar(
                radius: 28,
                backgroundColor: Colors.amber,
                child: Text('CD', style: TextStyle(color: Colors.white)),
              ),
            ],
          ),
        ],
      ),
    );
  }
}
